@click.option("--into-sessions", multiple=True, help="Place each source into a session.")
@click.option("--on-conflict", type=click.Choice(["error", "add-runs"]), default="error")
@common_options
def merge(
    sources: tuple[str, ...],
    output: str,
    into_sessions: tuple[str, ...],
    on_conflict: str,
    dry_run: bool,
    json_output: bool,
    verbose: int,
    quiet: bool,
    force: bool,
    schema_version: str | None,
) -> None:
    """Merge multiple BIDS datasets."""
    sessions = list(into_sessions) if into_sessions else None

    result = merge_datasets(
        list(sources),
        output,
        into_sessions=sessions,
        on_conflict=on_conflict,  # type: ignore[arg-type]
        dry_run=dry_run,
    )

    if json_output:
        click.echo(json.dumps({
            "success": result.success,
            "changes": [{"action": c.action, "detail": c.detail} for c in result.changes],
            "errors": result.errors,
        }, indent=2))
    else:
        prefix = "[DRY RUN] " if dry_run else ""
        for change in result.changes:
            click.echo(f"{prefix}{change.detail}")
        for e in result.errors:
            click.echo(f"Error: {e}", err=True)

    if not result.success:
        sys.exit(2)

